    {
      "span_start": 950,
      "span_end": 1050,
      "span_text": "فَلَمَّا بَلَغَ مَعَهُ السَّعْيَ قَالَ يَا بُنَيَّ إِنِّي أَرَى فِي الْمَنَامِ أَنِّي أَذْبُحَكَ فَانْظُرْ مَاذَا تَرَى قَالَ يَا أَبَتِ افعل مَا تُؤْمَرْ سَتَجِدُنِي إِنْ شَاءَ اللَّهُ مِنَ الصَّابِرِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1060,
      "span_end": 1100,
